import React, { useState } from 'react';
import Home from './pages/Home';
import Login from './pages/Login';
import 'bootstrap/dist/css/bootstrap.min.css';

function App() {
  const [currentPage, setCurrentPage] = useState('home');

  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#f4f7f6' }}>

      {/* 1. Varcha Blue Bar */}
      <nav className="navbar navbar-dark px-4 py-2" style={{ backgroundColor: '#0056b3' }}>
        <div className="container-fluid">
          <span className="navbar-brand fw-bold fs-4">Apni Manzil</span>
          <div className="ms-auto d-flex align-items-center gap-3">
            <span className="text-white small d-none d-md-block" style={{cursor:'pointer'}}>Home</span>
            <span className="text-white small d-none d-md-block" style={{cursor:'pointer'}}>Tracking</span>
            <button onClick={() => setCurrentPage('login')} className="btn btn-success btn-sm px-3 rounded shadow-sm">Login</button>
          </div>
        </div>
      </nav>

      {/* 2. Khaliil White Menu Bar (Buttons) */}
      <div className="bg-white border-bottom shadow-sm py-2 px-3 overflow-auto">
        <div className="container-fluid d-flex justify-content-center gap-4 text-nowrap">
          {["Home", "Book Shipment", "Courier Services", "Transport", "International", "Business MSME", "Tracking", "Pricing", "Support"].map((item) => (
            <span key={item} style={{ cursor: 'pointer', fontSize: '14px', fontWeight: '500', color: '#333' }} 
                  className="hover-link" onClick={() => setCurrentPage('home')}>
              {item}
            </span>
          ))}
        </div>
      </div>

      {/* Main Content */}
      <main style={{
        backgroundImage: `linear-gradient(rgba(255, 255, 255, 0.8), rgba(255, 255, 255, 0.8)), url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?q=80&w=2000')`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        minHeight: '80vh'
      }}>
        {currentPage === 'home' ? <Home /> : <Login />}
      </main>

    </div>
  );
}

export default App;
